import {KitsDropdown} from "../../../../form/selects";
import type {FilterEl} from "../Filter";
import {useLanguage} from "../../../../_compat";

const DropdownFilter: FilterEl<{
    list:
        | {
        label: string;
        value: any;
    }[]
        | undefined;
    filter?: boolean;
}> = ({list, filter = true, ...options}) => {
    const {t} = useLanguage();
    const listArray = Array.isArray(list) ? list : [];
    return (
        <KitsDropdown
            attached
            id={"filter-dropdown"}
            value={options.value}
            list={listArray}
            withFilter={filter}
            onChange={(e: any) => options.filterApplyCallback(e.value)}
            placeholder={t("any")}
            inputSize="sm"
        />
    );
};

export default DropdownFilter;
